patch.new_text:
func set_holder(active: bool) -> void:
	if _holder:
		_holder.visible = active
		for trigger in _triggers:
			if trigger is Area3D:
				trigger.set_deferred("monitoring", active)
				trigger.set_deferred("monitorable", active)
